  const { token } = await params;
  if (!token || token.length < 16) {
    return NextResponse.json({ error: "invalid token" }, { status: 404 });
  }

  const mode = request.nextUrl.searchParams.get("mode") === "detailed" ? "detailed" : "summary";

  const sb = createSupabaseServiceClient();
  const { data, error } = await sb
    .from("scans")
    .select("report_html,result_json,project_name,project_hash")
    .eq("share_token", token)
    .limit(1);
  if (error) {
    console.error("[r/html] lookup failed:", error.message);
    return NextResponse.json({ error: "database error" }, { status: 500 });
  }
  const scan = data?.[0] as
    | { report_html: string | null; result_json: Record<string, unknown> | null; project_name: string | null; project_hash: string }
    | undefined;

  let html: string | null = null;

  if (scan?.result_json) {
    try {
      // @ts-expect-error, @vibedrift/cli/render has no .d.ts yet
      const { renderHtmlReport } = await import("@vibedrift/cli/render");
      const displayName = scan.project_name || scan.project_hash?.slice(0, 12) || "project";
      const adapted = adaptResultJson(scan.result_json, displayName);
      html = renderHtmlReport(adapted, mode, {
        summaryUrl: `/api/r/${token}/html`,
        detailedUrl: `/api/r/${token}/html?mode=detailed`,
      });
    } catch (e) {
      console.error("[r/html] render from result_json failed:", e);
    }
  }

  if (!html && scan?.report_html) {
    html = scan.report_html;
  }

  if (!html) {
    return NextResponse.json({ error: "not found" }, { status: 404 });
  }

  return new NextResponse(html, {
    status: 200,
    headers: {
      "Content-Type": "text/html; charset=utf-8",
      "Cache-Control": "public, max-age=300",
      "Content-Security-Policy":
        "default-src 'self' 'unsafe-inline' 'unsafe-eval' data:; style-src 'unsafe-inline'; img-src * data:; connect-src 'self' https://vibedrift-api.fly.dev",
    },
  });
}

fnB.body:
  const { id } = await params;
  const mode = request.nextUrl.searchParams.get("mode") === "detailed" ? "detailed" : "summary";

  const auth = await createSupabaseServerClient();
  const {
    data: { user },
  } = await auth.auth.getUser();
  if (!user?.email) {
    return NextResponse.json({ error: "unauthorized" }, { status: 401 });
  }

  const sb = createSupabaseServiceClient();

  const { data: userRows } = await sb
    .from("users")
    .select("id")
    .eq("email", user.email.toLowerCase())
    .limit(1);
  const userId = (userRows?.[0] as { id: string } | undefined)?.id;
  if (!userId) {
    return NextResponse.json({ error: "account not provisioned" }, { status: 404 });
  }

  // Render from result_json for consistent UI. Falls back to report_html
  // only if rendering fails (e.g. incompatible result_json schema).
  const { data: scanRows, error } = await sb
    .from("scans")
    .select("report_html,result_json,project_name,project_hash")
    .eq("id", id)
    .eq("user_id", userId)
    .limit(1);
  if (error) {
    console.error("[scans/html] select failed:", error.message);
    return NextResponse.json({ error: "database error" }, { status: 500 });
  }

  const scan = scanRows?.[0] as { report_html: string | null; result_json: Record<string, unknown> | null; project_name: string | null; project_hash: string } | undefined;

  let html: string | null = null;

  // Try rendering from result_json with adapter
  if (scan?.result_json) {
    try {
      // @ts-expect-error, @vibedrift/cli/render has no .d.ts yet
      const { renderHtmlReport } = await import("@vibedrift/cli/render");
      // Use project_name from DB column (privacy-safe) or short hash
      const displayName = scan.project_name || scan.project_hash?.slice(0, 12) || "project";
      const adapted = adaptResultJson(scan.result_json, displayName);
      html = renderHtmlReport(adapted, mode, {
        summaryUrl: `/api/scans/${id}/html`,
        detailedUrl: `/api/scans/${id}/html?mode=detailed`,
      });
    } catch (e) {
      console.error("[scans/html] render from result_json failed:", e);
    }
  }

  // Fallback to stored HTML if rendering failed
  if (!html && scan?.report_html) {
    html = scan.report_html;
  }

  if (!html) {
    return NextResponse.json(
      { error: "no report data available for this scan" },
      { status: 404 },
    );
  }

  return new NextResponse(html, {
    status: 200,
    headers: {
      "Content-Type": "text/html; charset=utf-8",
      "Cache-Control": "private, no-cache",
      "Content-Security-Policy":
        "default-src 'self' 'unsafe-inline' 'unsafe-eval' data:; style-src 'unsafe-inline'; img-src * data:; connect-src 'self' https://vibedrift-api.fly.dev",
    },
  });
}

